/**
 * FINIFY AI: CORE TERMINAL TOKENS
 * Matches the Dark Charcoal × Emerald premium aesthetic.
 */

export const darkTheme = {
  // Surface Hierarchy
  '--bg-color': '#0a0a0a',            // Deep Charcoal Base
  '--card-bg': '#141414',             // Elevated Surface
  '--input-bg': 'rgba(0, 0, 0, 0.4)',  // Recessed Terminal Input
  
  // Branding & Interaction
  '--primary-accent': '#10b981',      // Emerald 500
  '--primary-hover': '#34d399',       // Emerald 400
  '--accent-glow': 'rgba(16, 185, 129, 0.15)',
  
  // Typography
  '--text-main': '#f9fafb',
  '--text-muted': '#6b7280',
  
  // Infrastructure
  '--border-color': 'rgba(255, 255, 255, 0.08)',
  '--card-shadow': '0 20px 40px rgba(0, 0, 0, 0.6)',
};

export const lightTheme = {
  // Silver Terminal Variant (Fallback)
  '--bg-color': '#f3f4f6',           
  '--card-bg': '#ffffff',
  '--primary-accent': '#059669',      // High-contrast Emerald
  '--text-main': '#111827',
  '--border-color': '#e5e7eb',
};
